#include <iostream>
#include <cstdlib>

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    if (b == 0) {
        std::cerr << "Error: division by zero.\n";
        std::exit(EXIT_FAILURE);
    }

    std::cout << "Result: " << a / b << "\n";
    return 0;
}

