solution_code:
#include <iostream>
#include <cstdlib>

void validateRange(int value, int minVal, int maxVal) {
    if (value < minVal || value > maxVal) {
        std::cerr << "Out of range.\n";
        std::exit(EXIT_FAILURE);
    }
}

int main() {
    int value{}, minVal{}, maxVal{};
    std::cin >> value >> minVal >> maxVal;

    validateRange(value, minVal, maxVal);

    std::cout << "Valid: " << value << "\n";
    return 0;
}
